import React, { useState } from 'react';
import Sidebar from './Sidebar';
import Header from './Header';
import MLModelStatus from './MLModelStatus';
import ModelDetails from './ModelDetails';
import MLPerformanceChart from './MLPerformanceChart';
import DashboardView from './DashboardView';
import SimulationView from './SimulationView';
import DetectionView from './DetectionView';
import TransactionsView from './TransactionsView';

const Dashboard = () => {
  const [activeSection, setActiveSection] = useState('Dashboard');
  const [simulatedTransactions, setSimulatedTransactions] = useState([]);

  const handleNavigate = (section) => {
    setActiveSection(section);
  };

  const handleRunBatch = (params) => {
    console.log('Running simulation with params:', params);

    // Simulate API call and generation
    const newTxns = Array.from({ length: params.batchSize }).map((_, i) => ({
      id: `SIM-${Math.floor(Math.random() * 10000)}`,
      time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      merchant: ['Amazon', 'Apple Store', 'Netflix', 'Unknown Vendor', 'Local Cafe'][Math.floor(Math.random() * 5)],
      amount: `$${(Math.random() * params.maxAmount).toFixed(2)}`,
      location: ['New York, US', 'London, UK', 'Dubai, AE', 'Remote'][Math.floor(Math.random() * 4)],
      risk: Math.floor(Math.random() * 100),
      status: Math.random() * 100 < params.fraudRatio ? 'flagged' : 'approved'
    }));

    setSimulatedTransactions(prev => [...newTxns, ...prev]);
    setActiveSection('Transactions'); // Switch to transactions to show results
  };

  const renderContent = () => {
    switch (activeSection) {
      case 'Dashboard':
        return <DashboardView transactions={simulatedTransactions} />;
      case 'Simulation':
        return <SimulationView onRunBatch={handleRunBatch} />;
      case 'Detection':
        return <DetectionView />;
      case 'Analytics':
        return (
          <div style={{ padding: '2rem' }}>
            <MLModelStatus />
            <ModelDetails />
            <MLPerformanceChart />
          </div>
        );
      case 'Transactions':
        return <TransactionsView transactions={simulatedTransactions} />;
      default:
        return (
          <div style={{ padding: '4rem', textAlign: 'center' }}>
            <h2 style={{ fontSize: '1.5rem', color: '#94a3b8' }}>{activeSection} section is under development</h2>
          </div>
        );
    }
  };

  return (
    <div style={{ 
      display: 'flex', 
      minHeight: '100vh', 
      backgroundColor: '#0f172a', 
      color: 'white', 
      fontFamily: 'Inter, system-ui, -apple-system, sans-serif' 
    }}>
      <Sidebar activeSection={activeSection} onNavigate={handleNavigate} />
      <main style={{ flex: 1, display: 'flex', flexDirection: 'column', overflowY: 'auto' }}>
        <Header activeSection={activeSection} />
        {renderContent()}
      </main>
    </div>
  );
};

export default Dashboard;
